mapper.select:
SELECT t.id as taskId, t.task_name as taskName, COUNT(r.id) as errorCount FROM api_task t INNER JOIN api_response r ON t.id = r.task_id WHERE r.status = 'ERROR' AND r.execute_time >= NOW() - INTERVAL '${days} days'
AND t.id = #{taskId}
GROUP BY t.id, t.task_name ORDER BY errorCount DESC LIMIT 10

SELECT TO_CHAR(execute_time, 'YYYY-MM-DD') as date, COUNT(*) as errorCount FROM api_response WHERE all_assertions_passed = false AND execute_time >= NOW() - INTERVAL '${days} days'
AND task_id = #{taskId}
GROUP BY TO_CHAR(execute_time, 'YYYY-MM-DD') ORDER BY date ASC
